import{_ as s,c as a,o as t,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"3 Ways to Run Pipelines with AI Assistants","description":"Learn to run Agent App Factory pipelines with OpenCode, Cursor, and other AI assistants. Covers startup methods, command formats, use cases, and troubleshooting.","frontmatter":{"title":"3 Ways to Run Pipelines with AI Assistants","sidebarTitle":"3 Ways to Run","subtitle":"3 Ways to Run Agent App Factory Pipelines with AI Assistants","description":"Learn to run Agent App Factory pipelines with OpenCode, Cursor, and other AI assistants. Covers startup methods, command formats, use cases, and troubleshooting.","tags":["AI Assistant","OpenCode","Cursor","Pipeline Execution"],"prerequisite":["start-installation"],"order":60},"headers":[],"relativePath":"hyz1992/agent-app-factory/platforms/other-ai-assistants/index.md","filePath":"hyz1992/agent-app-factory/platforms/other-ai-assistants/index.md"}'),i={name:"hyz1992/agent-app-factory/platforms/other-ai-assistants/index.md"};function o(l,e,r,p,c,d){return t(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="_3-ways-to-run-pipelines-with-ai-assistants" tabindex="-1">3 Ways to Run Pipelines with AI Assistants <a class="header-anchor" href="#_3-ways-to-run-pipelines-with-ai-assistants" aria-label="Permalink to &quot;3 Ways to Run Pipelines with AI Assistants&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>✅ Launch and run Factory pipelines with OpenCode</li><li>✅ Run pipelines with Cursor</li><li>✅ Understand command format differences across AI assistants</li><li>✅ Choose the right AI assistant for your use case</li></ul><h2 id="your-current-challenge" tabindex="-1">Your Current Challenge <a class="header-anchor" href="#your-current-challenge" aria-label="Permalink to &quot;Your Current Challenge&quot;">​</a></h2><p>You&#39;ve initialized a Factory project, but don&#39;t know how to run the pipeline with AI assistants other than Claude Code. OpenCode and Cursor are mainstream AI programming assistants—can they run Factory pipelines? What are the differences in startup methods and command formats?</p><h2 id="when-to-use-each-approach" tabindex="-1">When to Use Each Approach <a class="header-anchor" href="#when-to-use-each-approach" aria-label="Permalink to &quot;When to Use Each Approach&quot;">​</a></h2><table tabindex="0"><thead><tr><th>AI Assistant</th><th>Recommended Use Case</th><th>Advantages</th></tr></thead><tbody><tr><td><strong>Claude Code</strong></td><td>Most stable Agent mode experience</td><td>Native Agent mode support, clear command format</td></tr><tr><td><strong>OpenCode</strong></td><td>Cross-platform users, flexible AI tools</td><td>Cross-platform, Agent mode support</td></tr><tr><td><strong>Cursor</strong></td><td>VS Code power users, VS Code ecosystem</td><td>High integration, seamless switching</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Core Principle</p><p>All AI assistants execute with the same logic: <strong>Read Agent Definition → Execute Pipeline → Generate Artifacts</strong>. The only differences are in startup methods and command formats.</p></div><h2 id="🎒-prerequisites" tabindex="-1">🎒 Prerequisites <a class="header-anchor" href="#🎒-prerequisites" aria-label="Permalink to &quot;🎒 Prerequisites&quot;">​</a></h2><p>Before starting, ensure:</p><ul><li>✅ <a href="./../../start/installation/">Installation &amp; Configuration</a> completed</li><li>✅ Project initialized with <code>factory init</code></li><li>✅ OpenCode or Cursor installed (at least one)</li></ul><h2 id="core-concept-ai-assistants-as-pipeline-execution-engines" tabindex="-1">Core Concept: AI Assistants as Pipeline Execution Engines <a class="header-anchor" href="#core-concept-ai-assistants-as-pipeline-execution-engines" aria-label="Permalink to &quot;Core Concept: AI Assistants as Pipeline Execution Engines&quot;">​</a></h2><p>The <strong>AI assistant</strong> serves as the pipeline execution engine, responsible for interpreting Agent definitions and generating artifacts. The core workflow includes five steps: first read <code>.factory/pipeline.yaml</code> to understand the stage order, then load the orchestrator to grasp execution constraints and permission check rules, next load the corresponding Agent definition file based on current state, then execute Agent commands to generate artifacts and verify exit conditions, and finally wait for user confirmation before proceeding to the next stage.</p><div class="info custom-block"><p class="custom-block-title">Important: AI Assistant Must Support Agent Mode</p><p>Factory pipelines rely on AI assistants that can understand and execute complex Markdown instructions. All supported AI assistants (Claude Code, OpenCode, Cursor) have Agent mode capabilities.</p></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-running-pipelines-with-opencode" tabindex="-1">Step 1: Running Pipelines with OpenCode <a class="header-anchor" href="#step-1-running-pipelines-with-opencode" aria-label="Permalink to &quot;Step 1: Running Pipelines with OpenCode&quot;">​</a></h3><h4 id="automatic-startup-recommended" tabindex="-1">Automatic Startup (Recommended) <a class="header-anchor" href="#automatic-startup-recommended" aria-label="Permalink to &quot;Automatic Startup (Recommended)&quot;">​</a></h4><p>If you have OpenCode CLI installed globally:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Execute in project root directory</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><p><code>factory init</code> will automatically detect and launch OpenCode, passing the following prompt:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请阅读.factory/pipeline.yaml和.factory/agents/orchestrator.checkpoint.md，启动流水线，帮我将产品想法碎片转化为可运行的应用，接下来我将会输入想法碎片。注意：Agent引用的skills/和policies/文件需要先查找.factory/目录，再查找根目录。</span></span></code></pre></div><p><strong>You should see</strong>:</p><ul><li>Terminal displays <code>Starting OpenCode...</code></li><li>OpenCode window opens automatically</li><li>Prompt already pasted in the input box</li></ul><h4 id="manual-startup" tabindex="-1">Manual Startup <a class="header-anchor" href="#manual-startup" aria-label="Permalink to &quot;Manual Startup&quot;">​</a></h4><p>If automatic startup fails, you can manually operate:</p><ol><li>Open the OpenCode application</li><li>Open your Factory project directory</li><li>Copy the following prompt to the OpenCode input box:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请阅读.factory/pipeline.yaml和.factory/agents/orchestrator.checkpoint.md，启动流水线，帮我将产品想法碎片转化为可运行的应用，接下来我将会输入想法碎片。注意：Agent引用的skills/和policies/文件需要先查找.factory/目录，再查找根目录。</span></span></code></pre></div><ol start="4"><li>Press Enter to execute</li></ol><h4 id="continuing-pipeline-execution" tabindex="-1">Continuing Pipeline Execution <a class="header-anchor" href="#continuing-pipeline-execution" aria-label="Permalink to &quot;Continuing Pipeline Execution&quot;">​</a></h4><p>If the pipeline has run to a certain stage, you can use the <code>factory run</code> command to continue:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># View current state and generate instructions</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or start from a specific stage</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prd</span></span></code></pre></div><p>OpenCode will display instructions similar to Claude Code:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🤖 AI Assistant Instructions:</span></span>
<span class="line"><span>──────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>This is an Agent Factory project. Please:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Read .factory/pipeline.yaml</span></span>
<span class="line"><span>2. Read .factory/agents/orchestrator.checkpoint.md</span></span>
<span class="line"><span>3. Read .factory/config.yaml</span></span>
<span class="line"><span>4. Execute pipeline from: bootstrap</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Note: Check .factory/ first for skills/policies/ references, then root directory.</span></span></code></pre></div><h3 id="step-2-running-pipelines-with-cursor" tabindex="-1">Step 2: Running Pipelines with Cursor <a class="header-anchor" href="#step-2-running-pipelines-with-cursor" aria-label="Permalink to &quot;Step 2: Running Pipelines with Cursor&quot;">​</a></h3><p>Cursor is a VS Code-based AI programming assistant that uses the Composer feature to run Factory pipelines.</p><h4 id="cursor-detection" tabindex="-1">Cursor Detection <a class="header-anchor" href="#cursor-detection" aria-label="Permalink to &quot;Cursor Detection&quot;">​</a></h4><p>The Factory CLI automatically detects the Cursor environment (via <code>CURSOR</code> or <code>CURSOR_API_KEY</code> environment variables).</p><h4 id="running-with-composer" tabindex="-1">Running with Composer <a class="header-anchor" href="#running-with-composer" aria-label="Permalink to &quot;Running with Composer&quot;">​</a></h4><ol><li>Open your Factory project directory in Cursor</li><li>Execute the <code>factory run</code> command:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div><ol start="3"><li>The terminal will display Cursor-specific instructions:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🤖 Cursor Instructions:</span></span>
<span class="line"><span>──────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>This is an Agent Factory project. Use Cursor Composer to:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. @ReadFile .factory/pipeline.yaml</span></span>
<span class="line"><span>2. @ReadFile .factory/agents/orchestrator.checkpoint.md</span></span>
<span class="line"><span>3. @ReadFile .factory/config.yaml</span></span>
<span class="line"><span>   (Note: Check .factory/ first for skills/policies/ references)</span></span>
<span class="line"><span>4. Execute pipeline from: bootstrap</span></span></code></pre></div><ol start="4"><li>Copy these instructions to the Cursor Composer input box</li><li>Execute</li></ol><h4 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h4><ul><li>Cursor Composer window is open</li><li>Pipeline starts executing, displaying current stage (e.g., <code>Running: bootstrap</code>)</li><li>Artifacts generated (e.g., <code>input/idea.md</code>)</li></ul><h3 id="step-3-understanding-command-formats-across-ai-assistants" tabindex="-1">Step 3: Understanding Command Formats Across AI Assistants <a class="header-anchor" href="#step-3-understanding-command-formats-across-ai-assistants" aria-label="Permalink to &quot;Step 3: Understanding Command Formats Across AI Assistants&quot;">​</a></h3><p>While the execution logic is the same, different AI assistants have slightly different command formats:</p><table tabindex="0"><thead><tr><th>Operation</th><th>Claude Code Format</th><th>Cursor Format</th><th>Other AI Assistants (OpenCode, etc.)</th></tr></thead><tbody><tr><td>Read file</td><td><code>Read(filePath)</code></td><td><code>@ReadFile filePath</code></td><td><code>Read filePath</code></td></tr><tr><td>Read multiple files</td><td><code>Read(file1)</code>, <code>Read(file2)</code></td><td><code>@ReadFile file1</code>, <code>@ReadFile file2</code></td><td>-</td></tr><tr><td>Write file</td><td><code>Write(filePath, content)</code></td><td>Direct write</td><td>-</td></tr><tr><td>Execute Bash command</td><td><code>Bash(command)</code></td><td>Direct execution</td><td>-</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Factory CLI Auto-Handles Formats</p><p>When you run <code>factory run</code>, the CLI automatically detects the current AI assistant type and generates the corresponding command format. You just need to copy and paste—no manual conversion required.</p></div><h3 id="step-4-continuing-from-a-specific-stage" tabindex="-1">Step 4: Continuing from a Specific Stage <a class="header-anchor" href="#step-4-continuing-from-a-specific-stage" aria-label="Permalink to &quot;Step 4: Continuing from a Specific Stage&quot;">​</a></h3><p>If the pipeline has completed previous stages, you can continue from any stage:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Start from UI stage</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ui</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Start from Tech stage</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tech</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Start from Code stage</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> code</span></span></code></pre></div><p>The Factory CLI will display the current pipeline status:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pipeline Status:</span></span>
<span class="line"><span>────────────────────────</span></span>
<span class="line"><span>Project: my-app</span></span>
<span class="line"><span>Status: Running</span></span>
<span class="line"><span>Current Stage: ui</span></span>
<span class="line"><span>Completed: bootstrap, prd</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Available stages:</span></span>
<span class="line"><span>  ✓ bootstrap</span></span>
<span class="line"><span>  ✓ prd</span></span>
<span class="line"><span>  → ui</span></span>
<span class="line"><span>  ○ tech</span></span>
<span class="line"><span>  ○ code</span></span>
<span class="line"><span>  ○ validation</span></span>
<span class="line"><span>  ○ preview</span></span></code></pre></div><h3 id="step-5-using-factory-continue-to-save-tokens-claude-code-only" tabindex="-1">Step 5: Using <code>factory continue</code> to Save Tokens (Claude Code Only) <a class="header-anchor" href="#step-5-using-factory-continue-to-save-tokens-claude-code-only" aria-label="Permalink to &quot;Step 5: Using \`factory continue\` to Save Tokens (Claude Code Only)&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Note</p><p>The <code>factory continue</code> command currently supports <strong>Claude Code only</strong>. If you&#39;re using OpenCode or Cursor, use <code>factory run</code> to manually start a new session.</p></div><p>To save tokens and avoid context accumulation, Claude Code supports multi-session execution:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Open a new terminal window and execute</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> continue</span></span></code></pre></div><p><strong>Execution Effect</strong>:</p><ul><li>Reads current state (<code>.factory/state.json</code>)</li><li>Automatically launches a new Claude Code window</li><li>Continues from the last paused stage</li></ul><p><strong>Use Cases</strong>:</p><ul><li>Completed Bootstrap → PRD, want to start a new session for the UI stage</li><li>Completed UI → Tech, want to start a new session for the Code stage</li><li>Any scenario where you need to avoid long conversation history</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="issue-1-opencode-startup-failure" tabindex="-1">Issue 1: OpenCode Startup Failure <a class="header-anchor" href="#issue-1-opencode-startup-failure" aria-label="Permalink to &quot;Issue 1: OpenCode Startup Failure&quot;">​</a></h3><p><strong>Symptoms</strong>: After executing <code>factory init</code>, OpenCode doesn&#39;t launch automatically.</p><p><strong>Causes</strong>:</p><ul><li>OpenCode CLI not added to PATH</li><li>OpenCode not installed</li></ul><p><strong>Solutions</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Manually launch OpenCode</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Windows</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">%LOCALAPPDATA%\\Programs\\OpenCode\\OpenCode.exe</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># macOS</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/Applications/OpenCode.app</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Linux (search by priority: /usr/bin/opencode first, then /usr/local/bin/opencode)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/bin/opencode</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># If the above path doesn&#39;t exist, try:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/local/bin/opencode</span></span></code></pre></div><p>Then manually copy and paste the prompt into OpenCode.</p><h3 id="issue-2-cursor-composer-not-recognizing-commands" tabindex="-1">Issue 2: Cursor Composer Not Recognizing Commands <a class="header-anchor" href="#issue-2-cursor-composer-not-recognizing-commands" aria-label="Permalink to &quot;Issue 2: Cursor Composer Not Recognizing Commands&quot;">​</a></h3><p><strong>Symptoms</strong>: Copy commands generated by <code>factory run</code> to Cursor Composer, but no response.</p><p><strong>Causes</strong>:</p><ul><li>Cursor Composer&#39;s <code>@ReadFile</code> syntax requires exact matching</li><li>File path might be incorrect</li></ul><p><strong>Solutions</strong>:</p><ol><li>Confirm using <code>@ReadFile</code> instead of <code>Read</code> or <code>ReadFile</code></li><li>Confirm file paths are relative to the project root</li><li>Try using absolute paths</li></ol><p><strong>Examples</strong>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># ✅ Correct</span></span>
<span class="line"><span>@ReadFile .factory/pipeline.yaml</span></span>
<span class="line"><span></span></span>
<span class="line"><span># ❌ Incorrect</span></span>
<span class="line"><span>Read(.factory/pipeline.yaml)</span></span>
<span class="line"><span>@readfile .factory/pipeline.yaml</span></span></code></pre></div><h3 id="issue-3-agent-fails-to-reference-skill-files" tabindex="-1">Issue 3: Agent Fails to Reference Skill Files <a class="header-anchor" href="#issue-3-agent-fails-to-reference-skill-files" aria-label="Permalink to &quot;Issue 3: Agent Fails to Reference Skill Files&quot;">​</a></h3><p><strong>Symptoms</strong>: Agent reports error finding <code>skills/bootstrap/skill.md</code> or <code>policies/failure.policy.md</code>.</p><p><strong>Causes</strong>:</p><ul><li>Incorrect Agent lookup path order</li><li>Both <code>.factory/</code> and root directory <code>skills/</code>, <code>policies/</code> exist in the project</li></ul><p><strong>Solutions</strong>: All AI assistants follow the same lookup order:</p><ol><li><strong>First search</strong> <code>.factory/skills/</code> and <code>.factory/policies/</code></li><li><strong>Fallback to root directory</strong> <code>skills/</code> and <code>policies/</code></li></ol><p>Ensure:</p><ul><li>After Factory project initialization, <code>skills/</code> and <code>policies/</code> have been copied to <code>.factory/</code></li><li>Agent definition explicitly states: &quot;Check <code>.factory/</code> directory first, then root directory&quot;</li></ul><h3 id="issue-4-pipeline-state-out-of-sync" tabindex="-1">Issue 4: Pipeline State Out of Sync <a class="header-anchor" href="#issue-4-pipeline-state-out-of-sync" aria-label="Permalink to &quot;Issue 4: Pipeline State Out of Sync&quot;">​</a></h3><p><strong>Symptoms</strong>: AI assistant shows a stage as completed, but <code>factory run</code> still displays <code>running</code> status.</p><p><strong>Causes</strong>:</p><ul><li>AI assistant manually updated <code>state.json</code>, inconsistent with CLI state</li><li>Multiple windows modified the state file simultaneously</li></ul><p><strong>Solutions</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Reset project state</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Re-run the pipeline</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Best Practice</p><p>Avoid running the same project&#39;s pipeline simultaneously in multiple AI assistant windows. This will cause state conflicts and artifact overwrites.</p></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><p>This lesson covered how to run Factory pipelines with OpenCode, Cursor, and other AI assistants:</p><p><strong>Core Points</strong>:</p><ul><li>✅ Factory supports multiple AI assistants (Claude Code, OpenCode, Cursor)</li><li>✅ <code>factory init</code> automatically detects and launches available AI assistants</li><li>✅ <code>factory run</code> generates corresponding commands based on the current AI assistant</li><li>✅ <code>factory continue</code> (Claude Code only) supports multi-session execution to save tokens</li><li>✅ All AI assistants follow the same execution logic, only command formats differ</li></ul><p><strong>Key Files</strong>:</p><ul><li><code>.factory/pipeline.yaml</code> — Pipeline definition</li><li><code>.factory/agents/orchestrator.checkpoint.md</code> — Orchestrator rules</li><li><code>.factory/state.json</code> — Pipeline state</li></ul><p><strong>Selection Recommendations</strong>:</p><ul><li>Claude Code: Most stable Agent mode experience (recommended)</li><li>OpenCode: First choice for cross-platform users</li><li>Cursor: VS Code power users</li></ul><h2 id="next-up" tabindex="-1">Next Up <a class="header-anchor" href="#next-up" aria-label="Permalink to &quot;Next Up&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../plugins/">Required Plugin Installation</a></strong>.</p><p>You will learn:</p><ul><li>Why superpowers and ui-ux-pro-max plugins need to be installed</li><li>How to install plugins automatically or manually</li><li>How to handle plugin installation failures</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line Range</th></tr></thead><tbody><tr><td>OpenCode launch</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/init.js#L152-L215" target="_blank" rel="noreferrer"><code>cli/commands/init.js</code></a></td><td>152-215</td></tr><tr><td>Claude Code launch</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/init.js#L119-L147" target="_blank" rel="noreferrer"><code>cli/commands/init.js</code></a></td><td>119-147</td></tr><tr><td>AI assistant detection</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/run.js#L105-L124" target="_blank" rel="noreferrer"><code>cli/commands/run.js</code></a></td><td>105-124</td></tr><tr><td>Command generation</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/run.js#L130-L183" target="_blank" rel="noreferrer"><code>cli/commands/run.js</code></a></td><td>130-183</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><code>CLAUDE_CODE</code> / <code>ANTHROPIC_API_KEY</code>: Claude Code environment variable detection (run.js:109-110)</li><li><code>CURSOR</code> / <code>CURSOR_API_KEY</code>: Cursor environment variable detection (run.js:114-115)</li><li><code>OPENCODE</code> / <code>OPENCODE_VERSION</code>: OpenCode environment variable detection (run.js:119-120)</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>launchClaudeCode(projectDir)</code>: Launch Claude Code and pass prompt (init.js:119-147)</li><li><code>launchOpenCode(projectDir)</code>: Launch OpenCode, supports both CLI and executable methods (init.js:152-215)</li><li><code>detectAIAssistant()</code>: Detect current AI assistant type via environment variables (run.js:105-124)</li><li><code>getAssistantInstructions(assistant, ...)</code>: Generate corresponding commands based on AI assistant type (run.js:130-183)</li></ul></details>`,106)])])}const g=s(i,[["render",o]]);export{u as __pageData,g as default};
